from .core import DataFlow


class AsyncFlow(DataFlow):
    def __init__(self):
        super().__init__()
        self._queue = []

    def process(self, record):
        self._queue.append(record)

    def flush(self):
        for record in self._queue:
            super().process(record)
        self._queue.clear()

