from .core import DataFlow


class ChainFlow(DataFlow):
    def __init__(self):
        super().__init__()
        self._chain = []

    def add_to_chain(self, flow):
        if not isinstance(flow, DataFlow):
            raise TypeError(f"Expected DataFlow, got {type(flow).__name__}")
        self._chain.append(flow)

    def process(self, record):
        super().process(record)
        for flow in self._chain:
            flow.process(record)

