from .core import DataFlow
from .log_flow import LogFlow


class FlowFactory:
    @staticmethod
    def create(flow_type, **kwargs):
        types = {
            "default": DataFlow,
            "log": LogFlow,
        }
        cls = types.get(flow_type)
        if cls is None:
            raise ValueError(f"Unknown flow type: {flow_type}")
        return cls(**kwargs)

    @staticmethod
    def create_default():
        return DataFlow()

