from .core import DataFlow


class FlowRouter:
    def __init__(self):
        self._routes = {}

    def add_route(self, key, flow):
        if not isinstance(flow, DataFlow):
            raise TypeError(f"Expected DataFlow, got {type(flow).__name__}")
        self._routes[key] = flow

    def route(self, key, record):
        flow = self._routes.get(key)
        if flow is None:
            raise KeyError(f"No route for key: {key}")
        flow.process(record)

    def broadcast(self, record):
        for flow in self._routes.values():
            flow.process(record)
